int main() {
    std::cout << "--- Robustness Issue: Missing Rule of Three (3139) ---\n";

    FileManager fm1("initial/path/file1.txt");
    fm1.displayPath();

    std::cout << "\nCreating fm2 as a copy of fm1 (shallow copy occurs):\n";
    FileManager fm2 = fm1; // Default copy constructor called
    fm2.displayPath();

    std::cout << "\nPassing fm1 to a function by value (another shallow copy occurs):\n";
    processFileManager(fm1); // Default copy constructor called for function parameter

    std::cout << "\n--- Using a block scope to control destruction order for another pair ---\n";
    {
        FileManager block_fm("block/scope/file.log");
        block_fm.displayPath();

        FileManager block_fm_copy = block_fm; // Shallow copy
        block_fm_copy.displayPath();

        std::cout << "Exiting block scope. block_fm_copy and block_fm will be destroyed.\n";
    } 

    std::cout << "\nMain function ending. fm2 and fm1 will be destroyed.\n";
    return 0;
}
